from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any


class EnvironmentInterface(ABC):
    """Abstract interface every environment adapter must implement."""

    @abstractmethod
    def read(self, key: str, **kwargs) -> Any:
        """Retrieve a value from the environment."""

    @abstractmethod
    def write(self, key: str, value: Any, **kwargs) -> None:
        """Write a value to the environment."""

    @abstractmethod
    def list(self, prefix: str = "") -> list[str]:
        """Enumerate keys available under a prefix."""


@dataclass
class EnvironmentResult:
    success: bool
    value: Any = None
    error: str | None = None

    @classmethod
    def ok(cls, value: Any) -> "EnvironmentResult":
        return cls(success=True, value=value)

    @classmethod
    def fail(cls, error: str) -> "EnvironmentResult":
        return cls(success=False, error=error)

import pathlib


class FileSystemAdapter(EnvironmentInterface):
    """Read/write files within a sandboxed root directory."""

    def __init__(self, root: str) -> None:
        self._root = pathlib.Path(root).resolve()

    def _safe_path(self, key: str) -> pathlib.Path:
        """Resolve key relative to root; reject path traversal."""
        resolved = (self._root / key).resolve()
        if not str(resolved).startswith(str(self._root)):
            raise PermissionError(f"Path traversal blocked: {key!r}")
        return resolved

    def read(self, key: str, **_) -> Any:
        path = self._safe_path(key)
        return path.read_text()

    def write(self, key: str, value: Any, **_) -> None:
        path = self._safe_path(key)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(str(value))

    def list(self, prefix: str = "") -> list[str]:
        base = self._safe_path(prefix) if prefix else self._root
        if not base.is_dir():
            return []
        return [
            str(p.relative_to(self._root))
            for p in base.rglob("*") if p.is_file()
        ]

import httpx


class HttpAdapter(EnvironmentInterface):
    """Thin adapter for REST APIs — GET maps to read(), POST to write()."""

    def __init__(self, base_url: str, headers: dict | None = None) -> None:
        self._base_url = base_url.rstrip("/")
        self._headers = headers or {}

    def read(self, key: str, **kwargs) -> Any:
        url = f"{self._base_url}/{key.lstrip('/')}"
        params = kwargs.get("params")
        r = httpx.get(url, headers=self._headers, params=params, timeout=10)
        r.raise_for_status()
        return r.json()

    def write(self, key: str, value: Any, **kwargs) -> None:
        url = f"{self._base_url}/{key.lstrip('/')}"
        method = kwargs.get("method", "post").lower()
        r = getattr(httpx, method)(
            url, json=value, headers=self._headers, timeout=10
        )
        r.raise_for_status()

    def list(self, prefix: str = "") -> list[str]:
        data = self.read(prefix)
        if isinstance(data, list):
            return [str(item.get("id", i)) for i, item in enumerate(data)]
        return []

import subprocess
import shlex


ALLOWED_COMMANDS = frozenset(["ls", "cat", "echo", "grep", "wc"])


class SandboxedShell(EnvironmentInterface):
    """
    Runs shell commands in a subprocess with an allow-list.
    Only the command name (first token) is checked against the list.
    """

    def read(self, key: str, **kwargs) -> Any:
        """key is treated as the shell command to run."""
        tokens = shlex.split(key)
        if not tokens or tokens[0] not in ALLOWED_COMMANDS:
            raise PermissionError(f"Command not allowed: {tokens[0]!r}")
        result = subprocess.run(
            tokens,
            capture_output=True,
            text=True,
            timeout=kwargs.get("timeout", 5),
        )
        if result.returncode != 0:
            raise RuntimeError(result.stderr.strip())
        return result.stdout

    def write(self, key: str, value: Any, **_) -> None:
        raise PermissionError("Shell writes are not supported")

    def list(self, prefix: str = "") -> list[str]:
        return self.read(f"ls {prefix}").splitlines()

class InMemoryEnvironment(EnvironmentInterface):
    """Drop-in test double — no filesystem, network, or process calls."""

    def __init__(self, initial: dict | None = None) -> None:
        self._store: dict[str, Any] = dict(initial or {})
        self.writes: list[tuple[str, Any]] = []   # spy: all write calls

    def read(self, key: str, **_) -> Any:
        if key not in self._store:
            raise KeyError(f"Key not found: {key!r}")
        return self._store[key]

    def write(self, key: str, value: Any, **_) -> None:
        self._store[key] = value
        self.writes.append((key, value))

    def list(self, prefix: str = "") -> list[str]:
        return [k for k in self._store if k.startswith(prefix)]

import anthropic


def run_file_agent(
    client: anthropic.Anthropic,
    task: str,
    env: EnvironmentInterface,
    max_steps: int = 10,
) -> str:
    """
    Agent that can read and write files via the environment interface.
    Tools are thin wrappers that delegate to env.read() and env.write().
    """
    tools = [
        {
            "name": "read_file",
            "description": "Read the contents of a file",
            "input_schema": {
                "type": "object",
                "properties": {"path": {"type": "string"}},
                "required": ["path"],
            },
        },
        {
            "name": "write_file",
            "description": "Write content to a file",
            "input_schema": {
                "type": "object",
                "properties": {
                    "path": {"type": "string"},
                    "content": {"type": "string"},
                },
                "required": ["path", "content"],
            },
        },
    ]

    def dispatch(name: str, args: dict) -> str:
        try:
            if name == "read_file":
                return env.read(args["path"])
            elif name == "write_file":
                env.write(args["path"], args["content"])
                return "written"
            return f"Unknown tool: {name}"
        except Exception as e:
            return f"error: {e}"

    messages = [{"role": "user", "content": task}]
    for _ in range(max_steps):
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        if resp.stop_reason == "end_turn":
            for b in resp.content:
                if b.type == "text":
                    return b.text
            return ""
        results = []
        for b in resp.content:
            if b.type == "tool_use":
                results.append({
                    "type": "tool_result",
                    "tool_use_id": b.id,
                    "content": dispatch(b.name, b.input),
                })
        messages.append({"role": "user", "content": results})
    return "[max_steps reached]"

import pytest


class TestInMemoryEnvironment:
    def test_read_write_roundtrip(self):
        env = InMemoryEnvironment()
        env.write("config/key", "value123")
        assert env.read("config/key") == "value123"

    def test_read_missing_raises_key_error(self):
        env = InMemoryEnvironment()
        with pytest.raises(KeyError):
            env.read("nonexistent")

    def test_list_filters_by_prefix(self):
        env = InMemoryEnvironment({"a/x": 1, "a/y": 2, "b/z": 3})
        assert set(env.list("a/")) == {"a/x", "a/y"}

    def test_writes_are_logged(self):
        env = InMemoryEnvironment()
        env.write("k", "v")
        assert env.writes == [("k", "v")]


class TestFileSystemAdapterPathTraversal:
    def test_traversal_blocked(self, tmp_path):
        adapter = FileSystemAdapter(str(tmp_path))
        with pytest.raises(PermissionError):
            adapter.read("../../etc/passwd")

    def test_read_write_within_root(self, tmp_path):
        adapter = FileSystemAdapter(str(tmp_path))
        adapter.write("notes/hello.txt", "hello")
        assert adapter.read("notes/hello.txt") == "hello"

import time
from enum import Enum


class CircuitState(Enum):
    CLOSED = "closed"      # normal: requests pass through
    OPEN = "open"          # tripped: reject requests immediately
    HALF_OPEN = "half_open"  # probe: allow one request to test recovery


class CircuitBreaker:
    """
    Wraps an EnvironmentInterface and trips open after consecutive failures.
    Prevents the agent from hammering a broken backend on every loop step.
    """
    def __init__(
        self,
        inner: "EnvironmentInterface",
        failure_threshold: int = 3,
        recovery_timeout_s: float = 30.0,
    ) -> None:
        self._inner = inner
        self._threshold = failure_threshold
        self._recovery_timeout = recovery_timeout_s
        self._state = CircuitState.CLOSED
        self._failures = 0
        self._opened_at: float | None = None

    def _transition(self, state: CircuitState) -> None:
        self._state = state
        if state == CircuitState.OPEN:
            self._opened_at = time.monotonic()

    def read(self, key: str, **kwargs):
        self._maybe_recover()
        if self._state == CircuitState.OPEN:
            raise RuntimeError("Circuit open — environment unavailable")
        try:
            result = self._inner.read(key, **kwargs)
            self._on_success()
            return result
        except Exception:
            self._on_failure()
            raise

    def write(self, key: str, value, **kwargs):
        self._maybe_recover()
        if self._state == CircuitState.OPEN:
            raise RuntimeError("Circuit open — environment unavailable")
        try:
            self._inner.write(key, value, **kwargs)
            self._on_success()
        except Exception:
            self._on_failure()
            raise

    def list(self, prefix: str = ""):
        return self._inner.list(prefix)

    def _maybe_recover(self):
        if (self._state == CircuitState.OPEN and self._opened_at is not None
                and time.monotonic() - self._opened_at >= self._recovery_timeout):
            self._transition(CircuitState.HALF_OPEN)

    def _on_success(self):
        self._failures = 0
        self._transition(CircuitState.CLOSED)

    def _on_failure(self):
        self._failures += 1
        if self._failures >= self._threshold:
            self._transition(CircuitState.OPEN)

class ReadOnlyEnvironment(EnvironmentInterface):
    """
    Decorator that makes any environment read-only.
    Useful for dry-run mode: the agent can reason and read
    but all write attempts are blocked.
    """

    def __init__(self, inner: "EnvironmentInterface") -> None:
        self._inner = inner

    def read(self, key: str, **kwargs):
        return self._inner.read(key, **kwargs)

    def write(self, key: str, value, **kwargs) -> None:
        raise PermissionError(
            f"Write blocked (read-only mode): key={key!r}"
        )

    def list(self, prefix: str = "") -> list[str]:
        return self._inner.list(prefix)


